        #region ˝âËřĹĐ¶Ď
        public static bool IsValidAndLocked(this IGlobalSaveData save, NamespaceID? unlockId)
        {
            return NamespaceID.IsValid(unlockId) && !save.IsUnlocked(unlockId);
        }
        public static bool IsInvalidOrUnlocked(this IGlobalSaveData save, NamespaceID? unlockId)
        {
            return !save.IsValidAndLocked(unlockId);
        }
        public static bool IsValidAndUnlocked(this IGlobalSaveData save, NamespaceID? unlockId)
        {
            return NamespaceID.IsValid(unlockId) && save.IsUnlocked(unlockId);
        }
        public static bool IsAllInvalidOrUnlocked(this IGlobalSaveData save, IEnumerable<NamespaceID>? unlocks)
        {
            if (unlocks == null || unlocks.Count() <= 0)
                return true;
            return unlocks.All(u => save.IsInvalidOrUnlocked(u));
        }
        #endregion

        #region µ÷ĘÔÓĂ»§
        public static bool IsDebugUser(this IGlobalSaveData saves)
        {
            var userName = saves.GetCurrentUserName();
            return saves.IsDebugUserName(userName);
        }
        public static bool IsDebugUserName(this IGlobalSaveData saves, string? name)
        {
            if (string.IsNullOrEmpty(name))
                return false;
            return debugUserNames.Any(n => n.Equals(name, System.StringComparison.OrdinalIgnoreCase));
        }
        public static readonly string[] debugUserNames = new string[]
        {
            "debug",
        };
        #endregion
